class Solution(object):
    def maximumStrongPairXor(self, nums):
        best = 0
        for i in range(len(nums)):
            for j in range(i, len(nums)):
                x, y = nums[i], nums[j]
                if abs(x - y) <= min(x, y):
                    best = max(best, x ^ y)
        return best
